import pytest

def zip_dicts(*dicts) -> dict:
    keys = set().union(*dicts)
    return {k: [d.get(k) for d in dicts] for k in keys}

# --- Tests ---

def test_zip_dicts_happy_path():
    """Test with multiple dictionaries containing the same keys."""
    d1 = {'a': 1, 'b': 2}
    d2 = {'a': 3, 'b': 4}
    d3 = {'a': 5, 'b': 6}

    result = zip_dicts(d1, d2, d3)

    expected = {
        'a': [1, 3, 5],
        'b': [2, 4, 6]
    }
    assert result == expected

def test_zip_dicts_mismatched_keys():
    """Test where dictionaries have different sets of keys (edge case)."""
    d1 = {'a': 1, 'b': 2}
    d2 = {'b': 3, 'c': 4}

    result = zip_dicts(d1, d2)

    # 'a' is missing in d2 -> None
    # 'c' is missing in d1 -> None
    expected = {
        'a': [1, None],
        'b': [2, 3],
        'c': [None, 4]
    }
    assert result == expected

def test_zip_dicts_empty_input():
    """Test with no arguments passed."""
    result = zip_dicts()
    assert result == {}

def test_zip_dicts_single_dict():
    """Test with only one dictionary provided."""
    d1 = {'a': 1, 'b': 2}
    result = zip_dicts(d1)
    expected = {'a': [1], 'b': [2]}
    assert result == expected

def test_zip_dicts_empty_dicts():
    """Test with empty dictionaries passed as arguments."""
    d1 = {}
    d2 = {'a': 1}
    result = zip_dicts(d1, d2)
    expected = {'a': [None, 1]}
    assert result == expected

def test_zip_dicts_none_values():
    """Test where keys explicitly map to None."""
    d1 = {'a': None}
    d2 = {'a': 1}
    result = zip_dicts(d1, d2)
    expected = {'a': [None, 1]}
    assert result == expected

def test_zip_dicts_invalid_input_type():
    """Test that passing non-dictionary objects raises an error."""
    # Passing an integer instead of a dict should raise AttributeError 
    # because the code calls .union() on dicts and .get() on elements.
    with pytest.raises(AttributeError):
        zip_dicts({'a': 1}, 123)

def test_zip_dicts_non_iterable_elements():
    """Test that passing something that isn't a dict raises an error during .get() call."""
    with pytest.raises(AttributeError):
        zip_dicts({'a': 1}, None)
